14	export function DataGrid({
15	    columns = [],
16	    pageData = null,
17	    pageSizeOptions = [10, 20, 50, 100],
18	    selectable = false,
19	    onPageChange,
20	    onSortChange,
21	    onSelectionChange,
22	    onRowClick,
23	}) {
24	    const rows = pageData?.items ?? [];
25	    const [sorting, setSorting] = useState([]);
26	    const [selectedKeys, setSelectedKeys] = useState([]);
27	    const { widths, getResizeProps } = useColumnResize(columns);
28	
29	    const tableColumns = useMemo(
30	        () =>
31	            columns.map((column) => ({
32	                accessorKey: column.key,
33	                header: column.header,
34	                cell: ({ row }) =>
35	                    column.cell
36	                        ? column.cell({ value: row.original[column.key], row: row.original })
37	                        : row.original[column.key],
38	                meta: column,
39	            })),
40	        [columns],
41	    );
42	
43	    const table = useReactTable({
44	        data: rows,
45	        columns: tableColumns,
46	        getCoreRowModel: getCoreRowModel(),
47	    });
48	
49	    const toggleSort = (column) => {
50	        if (!column.sortable) {
51	            return;
52	        }
53	
54	        const currentDirection = sorting[0]?.id === column.key ? sorting[0].desc : undefined;
55	        const nextDirection = currentDirection === undefined ? 'asc' : currentDirection === false ? 'desc' : '';
56	
57	        setSorting(nextDirection ? [{ id: column.key, desc: nextDirection === 'desc' }] : []);
58	        onSortChange?.({ active: column.key, direction: nextDirection });
59	    };
60	
61	    const isAllSelected = rows.length > 0 && selectedKeys.length === rows.length;
62	
63	    const updateSelection = (nextRows) => {
64	        setSelectedKeys(nextRows.map((row) => row.id ?? JSON.stringify(row)));
65	        onSelectionChange?.(nextRows);
66	    };
67	
68	    const toggleAll = () => {
69	        if (isAllSelected) {
70	            updateSelection([]);
71	            return;
72	        }
73	
74	        updateSelection(rows);
75	    };
76	
77	    const toggleRow = (row) => {
78	        const rowKey = row.id ?? JSON.stringify(row);
79	        const exists = selectedKeys.includes(rowKey);
80	        const nextRows = exists
81	            ? rows.filter((item) => (item.id ?? JSON.stringify(item)) !== rowKey)
82	            : rows.filter((item) => selectedKeys.includes(item.id ?? JSON.stringify(item))).concat(row);
83	
84	        updateSelection(nextRows);
85	    };
86	
87	    return (
88	        <section className='overflow-hidden rounded-lg border border-slate-200 bg-white shadow-sm'>
89	            <Table>
90	                <TableHeader>
91	                    <TableRow>
92	                        {selectable ? (
