94	                                <input
95	                                    type='checkbox'
96	                                    aria-label='Select all rows'
97	                                    checked={isAllSelected}
98	                                    onChange={toggleAll}
99	                                />
100	                            </TableHead>
101	                        ) : null}
102	                        {table.getHeaderGroups().map((headerGroup) =>
103	                            headerGroup.headers.map((header) => {
104	                                const meta = header.column.columnDef.meta;
105	                                const width = widths[meta.key] ?? meta.width;
106	
107	                                return (
108	                                    <TableHead
109	                                        key={header.id}
110	                                        className={getTextAlignClassName(meta.align)}
111	                                        style={width ? { width: `${width}px` } : undefined}
112	                                        {...getResizeProps(meta)}
113	                                    >
114	                                        {meta.sortable ? (
115	                                            <button
116	                                                type='button'
117	                                                aria-label={`Sort by ${meta.header}`}
118	                                                className='inline-flex items-center gap-1 text-inherit'
119	                                                onClick={() => toggleSort(meta)}
120	                                            >
121	                                                <span>{flexRender(header.column.columnDef.header, header.getContext())}</span>
122	                                                <span className='text-xs text-slate-400'>
123	                                                    {sorting[0]?.id === meta.key
124	                                                        ? sorting[0].desc
125	                                                            ? '↓'
126	                                                            : '↑'
127	                                                        : '↕'}
128	                                                </span>
129	                                            </button>
130	                                        ) : (
131	                                            flexRender(header.column.columnDef.header, header.getContext())
132	                                        )}
133	                                    </TableHead>
134	                                );
135	                            }),
136	                        )}
137	                    </TableRow>
138	                </TableHeader>
139	                <TableBody>
140	                    {table.getRowModel().rows.map((row) => {
141	                        const rowKey = row.original.id ?? JSON.stringify(row.original);
142	                        const checked = selectedKeys.includes(rowKey);
143	
144	                        return (
145	                            <TableRow
146	                                key={row.id}
147	                                data-state={checked ? 'selected' : undefined}
148	                                className='cursor-pointer'
149	                                onClick={() => onRowClick?.(row.original)}
150	                            >
151	                                {selectable ? (
152	                                    <TableCell className='w-14' onClick={(event) => event.stopPropagation()}>
153	                                        <input
154	                                            type='checkbox'
155	                                            aria-label={`Select row ${row.index + 1}`}
156	                                            checked={checked}
157	                                            onChange={() => toggleRow(row.original)}
158	                                        />
159	                                    </TableCell>
160	                                ) : null}
161	                                {row.getVisibleCells().map((cell) => {
162	                                    const meta = cell.column.columnDef.meta;
163	
164	                                    return (
165	                                        <TableCell
166	                                            key={cell.id}
167	                                            className={cn(getTextAlignClassName(meta.align))}
168	                                        >
169	                                            {flexRender(cell.column.columnDef.cell, cell.getContext())}
170	                                        </TableCell>
171	                                    );
172	                                })}
173	                            </TableRow>
174	                        );
175	                    })}
176	                </TableBody>
177	            </Table>
178	
179	            {pageData ? (
180	                <footer className='flex flex-wrap items-center justify-between gap-3 border-t border-slate-200 px-4 py-3'>
181	                    <div className='text-sm text-slate-500'>
182	                        Page {pageData.page} of {pageData.totalPages} · {pageData.totalElements} items
183	                    </div>
184	                    <div className='flex items-center gap-2'>
185	                        <select
186	                            aria-label='Page size'
187	                            className='h-9 rounded-md border border-slate-300 bg-white px-3 text-sm'
188	                            value={pageData.size}
189	                            onChange={(event) =>
190	                                onPageChange?.({
191	                                    page: 1,
192	                                    size: Number(event.target.value),
193	                                })
194	                            }
195	                        >
196	                            {pageSizeOptions.map((option) => (
197	                                <option key={option} value={option}>
198	                                    {option} / page
199	                                </option>
200	                            ))}
201	                        </select>
202	                        <Button
203	                            variant='outline'
204	                            disabled={pageData.page <= 1}
205	                            onClick={() => onPageChange?.({ page: pageData.page - 1, size: pageData.size })}
206	                        >
207	                            Previous page
208	                        </Button>
209	                        <Button
210	                            variant='outline'
211	                            disabled={pageData.page >= pageData.totalPages}
212	                            onClick={() => onPageChange?.({ page: pageData.page + 1, size: pageData.size })}
213	                        >
214	                            Next page
215	                        </Button>
216	                    </div>
217	                </footer>
218	            ) : null}
219	        </section>
220	    );
221	}
